761: 			r_error.expected = 0;
762: 			return Variant();
763: 		}
764: 		if (is_ref_counted()) {
765: 			r_error.error = Callable::CallError::CALL_ERROR_INVALID_METHOD;
766: 			ERR_FAIL_V_MSG(Variant(), "Can't free a RefCounted object.");
767: 		}
768: 
769: 		if (_lock_index.get() > 1) {
