788: 		switch (r_error.error) {
789: 			case Callable::CallError::CALL_OK:
790: 				return ret;
791: 			case Callable::CallError::CALL_ERROR_INVALID_METHOD:
792: 				break;
793: 			case Callable::CallError::CALL_ERROR_INVALID_ARGUMENT:
794: 			case Callable::CallError::CALL_ERROR_TOO_MANY_ARGUMENTS:
795: 			case Callable::CallError::CALL_ERROR_TOO_FEW_ARGUMENTS:
796: 			case Callable::CallError::CALL_ERROR_METHOD_NOT_CONST:
797: 				return ret;
798: 			case Callable::CallError::CALL_ERROR_INSTANCE_IS_NULL: {
799: 			}
800: 		}
801: 	}
802: 
