2022: Variant GDScriptInstance::callp(const StringName &p_method, const Variant **p_args, int p_argcount, Callable::CallError &r_error) {
2023: 	GDScript *sptr = script.ptr();
2024: 	if (unlikely(p_method == SceneStringName(_ready))) {
2025: 		// Call implicit ready first, including for the super classes recursively.
2026: 		_call_implicit_ready_recursively(sptr);
2027: 	}
2028: 	while (sptr) {
2029: 		if (likely(sptr->valid)) {
2030: 			HashMap<StringName, GDScriptFunction *>::Iterator E = sptr->member_functions.find(p_method);
2031: 			if (E) {
2032: 				return E->value->call(this, p_args, p_argcount, r_error);
2033: 			}
2034: 		}
2035: 		sptr = sptr->_base;
2036: 	}
2037: 
2038: 	r_error.error = Callable::CallError::CALL_ERROR_INVALID_METHOD;
2039: 	return Variant();
2040: }
