2042: void GDScriptInstance::notification(int p_notification, bool p_reversed) {
2043: 	if (unlikely(!script->valid)) {
2044: 		return;
2045: 	}
2046: 
2047: 	//notification is not virtual, it gets called at ALL levels just like in C.
2048: 	Variant value = p_notification;
2049: 	const Variant *args[1] = { &value };
2050: 
2051: 	List<GDScript *> pl;
2052: 	GDScript *sptr = script.ptr();
2053: 	while (sptr) {
2054: 		if (p_reversed) {
2055: 			pl.push_back(sptr);
2056: 		} else {
2057: 			pl.push_front(sptr);
2058: 		}
2059: 		sptr = sptr->_base;
2060: 	}
2061: 	for (GDScript *sc : pl) {
2062: 		if (likely(sc->valid)) {
2063: 			HashMap<StringName, GDScriptFunction *>::Iterator E = sc->member_functions.find(GDScriptLanguage::get_singleton()->strings._notification);
2064: 			if (E) {
2065: 				Callable::CallError err;
2066: 				E->value->call(this, args, 1, err);
2067: 				if (err.error != Callable::CallError::CALL_OK) {
2068: 					//print error about notification call
2069: 				}
2070: 			}
2071: 		}
2072: 	}
2073: }
