2075: String GDScriptInstance::to_string(bool *r_valid) {
2076: 	if (has_method(CoreStringName(_to_string))) {
2077: 		Callable::CallError ce;
2078: 		Variant ret = callp(CoreStringName(_to_string), nullptr, 0, ce);
2079: 		if (ce.error == Callable::CallError::CALL_OK) {
2080: 			if (ret.get_type() != Variant::STRING) {
2081: 				if (r_valid) {
2082: 					*r_valid = false;
2083: 				}
2084: 				ERR_FAIL_V_MSG(String(), "Wrong type for " + CoreStringName(_to_string) + ", must be a String.");
2085: 			}
2086: 			if (r_valid) {
2087: 				*r_valid = true;
2088: 			}
2089: 			return ret.operator String();
2090: 		}
2091: 	}
2092: 	if (r_valid) {
2093: 		*r_valid = false;
2094: 	}
2095: 	return String();
2096: }
