43: bool GDScriptCompiler::_is_class_member_property(CodeGen &codegen, const StringName &p_name) {
44: 	if (codegen.function_node && codegen.function_node->is_static) {
45: 		return false;
46: 	}
47: 
48: 	if (_is_local_or_parameter(codegen, p_name)) {
49: 		return false; //shadowed
50: 	}
51: 
52: 	return _is_class_member_property(codegen.script, p_name);
53: }
54: 
55: bool GDScriptCompiler::_is_class_member_property(GDScript *owner, const StringName &p_name) {
56: 	GDScript *scr = owner;
57: 	GDScriptNativeClass *nc = nullptr;
58: 	while (scr) {
59: 		if (scr->native.is_valid()) {
60: 			nc = scr->native.ptr();
61: 		}
62: 		scr = scr->_base;
63: 	}
64: 
65: 	ERR_FAIL_NULL_V(nc, false);
66: 
67: 	return ClassDB::has_property(nc->get_name(), p_name);
68: }
69: 
70: bool GDScriptCompiler::_is_local_or_parameter(CodeGen &codegen, const StringName &p_name) {
71: 	return codegen.parameters.has(p_name) || codegen.locals.has(p_name);
72: }
