78: 
79: 	error = p_error;
80: 	if (p_node) {
81: 		err_line = p_node->start_line;
82: 		err_column = p_node->leftmost_column;
83: 	} else {
84: 		err_line = 0;
85: 		err_column = 0;
86: 	}
87: }
