72: 	_FORCE_INLINE_ Variant has_default_argument(int p_arg) const {
73: 		int idx = p_arg - (argument_count - default_arguments.size());
74: 
75: 		if (idx < 0 || idx >= default_arguments.size()) {
76: 			return false;
77: 		} else {
78: 			return true;
79: 		}
